const PROCESSING_FEE = 5;
const FIRST_INSURANCE_SURCHARGE_PERCENT = 10;

interface Item {
  type: string;
}
interface QuoteStep {
  op: "quote";
  items: Item[];
}
interface Scenario {
  customer: { yearsWithMHPCO: number };
  steps: QuoteStep[];
}

const BASE_PREMIUM: Record<string, number> = {
  sword: 100,
  amulet: 60,
};

// Rounds up in MHPCO's favor; integer arithmetic avoids IEEE 754 drift.
const applyPercentSurchargeRoundedUp = (base: number, percent: number): number =>
  Math.ceil((base * (100 + percent)) / 100);

const quotePremium = (step: QuoteStep): number => {
  if (step.items.length === 0) return PROCESSING_FEE;
  const itemBase = BASE_PREMIUM[step.items[0].type];
  const withFirstInsurance = applyPercentSurchargeRoundedUp(itemBase, FIRST_INSURANCE_SURCHARGE_PERCENT);
  return withFirstInsurance + PROCESSING_FEE;
};

export const processScenario = (scenario: Scenario): unknown => {
  const results = scenario.steps.map((step) => ({ premium: quotePremium(step) }));
  return { results };
};
